// 1. Haal de array met 10 getallen op uit de Modbus-node
let registers = msg.payload; 

if (!Array.isArray(registers) || registers.length < 10) {
    node.error("Modbus gaf geen 10 registers terug. Controleer Quantity/Aantal.");
    return null;
}

        // 2. Maak een lege buffer aan van 20 bytes (10 registers * 2 bytes)
let buffer = Buffer.alloc(20);

        // 3. Schrijf de getallen weg als Big-Endian (High byte, Low byte)
for (let i = 0; i < 10; i++) {
    buffer.writeUInt16BE(registers[i], i * 2);
}

            // 4. Zet de buffer om naar een ASCII-tekst
let rawString = buffer.toString('ascii');

            // 5. Filter onzichtbare systeemtekens (zoals \u0000 of nullen) eruit
            // en vervang ze door spaties, zodat je '567' of het serienummer wél ziet
let cleanString = rawString.replace(/[\x00-\x1F\x7F-\x9F]/g, ' ').trim();

            // 6. Stuur de schone tekst door naar je dashboard of debug-venster
msg.payload = cleanString;
return msg;
